1	interface QuoteStep {
2	  op: "quote";
3	  items: { type: string }[];
4	}
5	
6	interface Scenario {
7	  customer: { yearsWithMHPCO: number };
8	  steps: QuoteStep[];
9	}
10	
11	const BASE_PREMIUM: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	};
18	
19	const FIRST_INSURANCE_RATE = 0.1;
20	const PROCESSING_FEE = 5;
21	
22	const RUNE_BLOCK_PREMIUM = 60;
23	
24	const policyBasePremium = (items: { type: string }[]): number => {
25	  const runeCount = items.filter((item) => item.type === "rune").length;
26	  const runeBase =
27	    runeCount === 3 ? RUNE_BLOCK_PREMIUM : runeCount * BASE_PREMIUM.rune;
28	  const otherBase = items
29	    .filter((item) => item.type !== "rune")
30	    .reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
31	  return runeBase + otherBase;
32	};
33	
34	const quotePremium = (step: QuoteStep): number => {
35	  const policyBase = policyBasePremium(step.items);
36	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
37	  return Math.ceil(policyBase + firstInsurance + PROCESSING_FEE);
38	};
39	
40	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
41	  return {
42	    results: scenario.steps.map((step) => ({ premium: quotePremium(step) })),
43	  };
44	};
